// packages/platform/shared/utils/get-global-with-dt-runtime.ts
var getGlobalWithDtRuntime = () => typeof globalThis !== "undefined" ? globalThis : window;

// packages/platform/app-environment/src/lib/get-app-id.ts
function getAppId() {
  const runtimeFunc = getGlobalWithDtRuntime().dtRuntime?.appEnvironment?.getAppId;
  if (typeof runtimeFunc === "function") {
    return runtimeFunc();
  } else {
    console.warn("Missing getAppId function from web runtime.");
    return "dt.missing.app.id";
  }
}

